export * as ToggleGroup from "./namespace";
export * from "./styles";
export * from "./toggle-group";

"use client";

import type { VariantProps } from "cva";
import { createContext, useContext } from "react";
import {
  composeRenderProps,
  ToggleButton,
  ToggleButtonGroup,
} from "react-aria-components";
import { ToggleStyles } from "~/registry/ui/toggle";
import { ToggleGroupStyles } from "./styles";

const ToggleGroupContext = createContext<VariantProps<typeof ToggleStyles>>({
  size: "default",
  variant: "default",
});

export type ToggleGroupRootProps = React.ComponentProps<
  typeof ToggleButtonGroup
> &
  VariantProps<typeof ToggleStyles>;

export function ToggleGroupRoot({
  className,
  variant,
  size,
  ...props
}: ToggleGroupRootProps) {
  return (
    <ToggleGroupContext.Provider value={{ size, variant }}>
      <ToggleButtonGroup
        className={composeRenderProps(className, (className) =>
          ToggleGroupStyles.Root({ className })
        )}
        data-size={size}
        data-slot="toggle-group-root"
        data-variant={variant}
        {...props}
      />
    </ToggleGroupContext.Provider>
  );
}

export interface ToggleGroupItemProps
  extends React.ComponentProps<typeof ToggleButton>,
    VariantProps<typeof ToggleStyles> {}

export function ToggleGroupItem({
  className,
  variant,
  size,
  ...props
}: ToggleGroupItemProps) {
  const context = useContext(ToggleGroupContext);
  const _variant = context.variant ?? variant;
  const _size = context.size ?? size;

  return (
    <ToggleButton
      className={composeRenderProps(className, (className) =>
        ToggleStyles({
          className: ToggleGroupStyles.Item({ className }),
          size: _size,
          variant: _variant,
        })
      )}
      data-size={_size}
      data-slot="toggle-group-item"
      data-variant={_variant}
      {...props}
    />
  );
}

import { cva } from "~/registry/lib/cva";

export const ToggleGroupStyles = {
  Item: cva({
    base: [
      "min-w-0 flex-1 shrink-0 rounded-none shadow-none",
      "first:rounded-l-md last:rounded-r-md",
      "focus:z-10 focus-visible:z-10",
      "data-[variant=outline]:border-l-0 data-[variant=outline]:first:border-l",
    ],
  }),
  Root: cva({
    base: [
      "group/toggle-group flex w-fit items-center rounded-md data-[variant=outline]:shadow-xs",
    ],
  }),
};

export {
  ToggleGroupItem as Item,
  ToggleGroupRoot as Root,
} from "./toggle-group";
